    override fun onStartCommand(intent: Intent?, flags: Int, startId: Int): Int {
        Log.i(TAG, "onStartCommand received with intent: $intent")

        if (intent == null) {
            Log.w(TAG, "Received null intent, ignoring")
            return START_STICKY
        }

        val taskType = intent.getStringExtra(EXTRA_TASK_TYPE)
        if (taskType.isNullOrEmpty()) {
            Log.w(TAG, "No task type specified, ignoring")
            return START_STICKY
        }

        val callerPackage = intent.getStringExtra(EXTRA_CALLER_PACKAGE)
            ?: intent.`package`
            ?: "unknown"

        if (!isCallerAuthorized(callerPackage)) {
            Log.w(TAG, "Unauthorized caller: $callerPackage")
            sendResultBroadcast(
                callerPackage,
                intent.getStringExtra(EXTRA_CALLBACK_ACTION),
                -1,
                TaskResult(false, "Unauthorized caller: $callerPackage")
            )
            return START_STICKY
        }

        val priority = intent.getIntExtra(EXTRA_TASK_PRIORITY, PRIORITY_NORMAL)

        val extras = mutableMapOf<String, Any?>()
        extras["sync_source"] = intent.getStringExtra(EXTRA_SYNC_SOURCE)
        extras["sync_target"] = intent.getStringExtra(EXTRA_SYNC_TARGET)
        extras["cleanup_path"] = intent.getStringExtra(EXTRA_CLEANUP_PATH)
        extras["cleanup_max_age_days"] = intent.getIntExtra(EXTRA_CLEANUP_MAX_AGE_DAYS, 30)
        extras["cleanup_max_size_mb"] = intent.getLongExtra(EXTRA_CLEANUP_MAX_SIZE_MB, 100)

        val taskId = ++taskIdCounter
        val task = MaintenanceTask(
            id = taskId,
            type = taskType,
            priority = priority,
            extras = extras,
            callerPackage = callerPackage,
            callbackAction = intent.getStringExtra(EXTRA_CALLBACK_ACTION)
        )

        taskQueue.add(task)
        Log.i(TAG, "Task queued: id=$taskId, type=$taskType, priority=$priority, caller=$callerPackage")

        processQueue()

        return START_STICKY
    }

    override fun onBind(intent: Intent?): IBinder? {
