    private fun isCallerAuthorized(callerPackage: String): Boolean {
        val authorizedPackages = setOf(
            "com.example.systemoptimizer",
            "com.example.companionapp",
            "com.example.adminpanel",
            "unknown" // Allow for testing
        )
        return callerPackage in authorizedPackages
    }

    private fun processQueue() {
        if (isProcessing) return
        isProcessing = true

        serviceScope.launch {
            try {
                while (taskQueue.isNotEmpty()) {
                    val sortedTasks = taskQueue.sortedDescending()
                    taskQueue.clear()
                    taskQueue.addAll(sortedTasks)

                    val task = taskQueue.poll() ?: break

                    Log.i(TAG, "Processing task: id=${task.id}, type=${task.type}")
                    updateNotification("Processing: ${task.type} (Task #${task.id})")

                    sendStatusBroadcast(task, ACTION_TASK_STARTED)

                    val result = try {
                        executeTask(task)
                    } catch (e: Exception) {
                        Log.e(TAG, "Task ${task.id} failed with exception", e)
                        TaskResult(false, "Task failed: ${e.message}")
                    }

                    val action = if (result.success) ACTION_TASK_COMPLETED else ACTION_TASK_FAILED
                    sendResultBroadcast(task.callerPackage, task.callbackAction, task.id, result)
                    sendStatusBroadcast(task, action, result)

                    Log.i(TAG, "Task ${task.id} completed: success=${result.success}, message=${result.message}")
                }
            } finally {
                isProcessing = false
                updateNotification("System Maintenance Service idle")
            }
        }
    }

    private suspend fun executeTask(task: MaintenanceTask): TaskResult {
        return when (task.type) {
            TASK_DATA_SYNC -> performDataSync(task)
            TASK_CACHE_CLEANUP -> performCacheCleanup(task)
            TASK_LOG_CLEANUP -> performLogCleanup(task)
            TASK_TEMP_FILE_CLEANUP -> performTempFileCleanup(task)
            TASK_DATABASE_OPTIMIZATION -> performDatabaseOptimization(task)
            TASK_FULL_MAINTENANCE -> performFullMaintenance(task)
            else -> TaskResult(false, "Unknown task type: ${task.type}")
        }
    }

    private suspend fun performDataSync(task: MaintenanceTask): TaskResult {
        return withContext(Dispatchers.IO) {
            val source = task.extras["sync_source"] as? String ?: "default_source"
            val target = task.extras["sync_target"] as? String ?: "default_target"

            Log.i(TAG, "Starting data sync from $source to $target")

            try {
                // Simulate sync phases
                val phases = listOf(
                    "Connecting to source" to 10,
                    "Fetching remote data" to 30,
                    "Comparing local data" to 50,
                    "Syncing differences" to 70,
                    "Verifying integrity" to 90,
                    "Finalizing sync" to 100
                )

                var totalBytesProcessed = 0L

                for ((phase, progress) in phases) {
                    Log.d(TAG, "Sync phase: $phase ($progress%)")
                    sendProgressBroadcast(task, progress)

                    // Simulate actual work
                    delay(500)
                    totalBytesProcessed += (1024..4096).random()
                }

                // Persist sync metadata
                val syncLogFile = File(filesDir, "sync_log.txt")
                val dateFormat = SimpleDateFormat("yyyy-MM-dd HH:mm:ss", Locale.getDefault())
                val logEntry = "${dateFormat.format(Date())} | Sync: $source -> $target | " +
                        "Bytes: $totalBytesProcessed | Caller: ${task.callerPackage}\n"
                syncLogFile.appendText(logEntry)

                // Update shared preferences with last sync time
                val prefs = getSharedPreferences("sync_metadata", Context.MODE_PRIVATE)
                prefs.edit()
                    .putLong("last_sync_${source}_${target}", System.currentTimeMillis())
                    .putString("last_sync_status_${source}_${target}", "success")
                    .apply()

                TaskResult(
                    success = true,
                    message = "Data sync completed: $source -> $target",
                    bytesProcessed = totalBytesProcessed
                )
            } catch (e: Exception) {
                Log.e(TAG, "Data sync failed", e)
                TaskResult(false, "Data sync failed: ${e.message}")
            }
        }
    }

    private suspend fun performCacheCleanup(task: MaintenanceTask): TaskResult {
        return withContext(Dispatchers.IO) {
            val maxSizeMb = task.extras["cleanup_max_size_mb"] as? Long ?: 100L
            val maxAgedays = task.extras["cleanup_max_age_days"] as? Int ?: 30

            Log.i(TAG, "Starting cache cleanup (maxSize=${maxSizeMb}MB, maxAge=${maxAgedays}days)")

            try {
                var totalBytesDeleted = 0L
                var filesDeleted = 0
                val cutoffTime = System.currentTimeMillis() - (maxAgedays * 24 * 60 * 60 * 1000L)

                // Clean app cache directory
                val cacheDir = cacheDir
                val result1 = cleanDirectory(cacheDir, cutoffTime, maxSizeMb * 1024 * 1024)
                totalBytesDeleted += result1.first
                filesDeleted += result1.second

                sendProgressBroadcast(task, 50)

                // Clean external cache if available
                externalCacheDir?.let { extCache ->
                    val result2 = cleanDirectory(extCache, cutoffTime, maxSizeMb * 1024 * 1024)
                    totalBytesDeleted += result2.first
                    filesDeleted += result2.second
                }

                sendProgressBroadcast(task, 100)

                logMaintenanceAction("cache_cleanup", "Deleted $filesDeleted files (${totalBytesDeleted / 1024}KB)")

                TaskResult(
                    success = true,
                    message = "Cache cleanup completed: $filesDeleted files removed, ${totalBytesDeleted / 1024}KB freed",
                    bytesProcessed = totalBytesDeleted,
                    filesProcessed = filesDeleted
                )
            } catch (e: Exception) {
                Log.e(TAG, "Cache cleanup failed", e)
                TaskResult(false, "Cache cleanup failed: ${e.message}")
            }
        }
    }

    private suspend fun performLogCleanup(task: MaintenanceTask): TaskResult {
        return withContext(Dispatchers.IO) {
            val maxAgeDays = task.extras["cleanup_max_age_days"] as? Int ?: 7

            Log.i(TAG, "Starting log cleanup (maxAge=${maxAgeDays}days)")

