                val mainLogFile = File(filesDir, "sync_log.txt")
                if (mainLogFile.exists() && mainLogFile.length() > 1024 * 1024) { // > 1MB
                    val lines = mainLogFile.readLines()
                    val trimmedLines = lines.takeLast(1000)
                    mainLogFile.writeText(trimmedLines.joinToString("\n"))
                    val savedBytes = mainLogFile.length()
                    totalBytesDeleted += savedBytes
                    Log.i(TAG, "Trimmed main log file, saved ${savedBytes / 1024}KB")
                }

                sendProgressBroadcast(task, 100)

                logMaintenanceAction("log_cleanup", "Cleaned $filesDeleted log files (${totalBytesDeleted / 1024}KB)")

                TaskResult(
                    success = true,
