                Log.e(TAG, "Log cleanup failed", e)
                TaskResult(false, "Log cleanup failed: ${e.message}")
            }
        }
    }

    private suspend fun performTempFileCleanup(task: MaintenanceTask): TaskResult {
        return withContext(Dispatchers.IO) {
            val cleanupPath = task.extras["cleanup_path"] as? String
            val maxAgeDays = task.extras["cleanup_max_age_days"] as? Int ?: 1

            Log.i(TAG, "Starting temp file cleanup (path=$cleanupPath, maxAge=${maxAgeDays}days)")

            try {
                var totalBytesDeleted = 0L
                var filesDeleted = 0
                val cutoffTime = System.currentTimeMillis() - (maxAgeDays * 24 * 60 * 60 * 1000L)

                // Clean specified path or default temp directories
                val targetDirs = if (cleanupPath != null) {
                    val targetDir = File(cleanupPath)
                    if (targetDir.exists() && isPathSafe(targetDir)) {
                        listOf(targetDir)
                    } else {
                        Log.w(TAG, "Invalid or unsafe cleanup path: $cleanupPath")
                        emptyList()
                    }
                } else {
                    listOfNotNull(
                        File(filesDir, "temp"),
                        File(cacheDir, "temp"),
                        externalCacheDir?.let { File(it, "temp") }
                    ).filter { it.exists() }
                }

                val totalDirs = targetDirs.size
                targetDirs.forEachIndexed { index, dir ->
                    val result = cleanDirectory(dir, cutoffTime, Long.MAX_VALUE, listOf(".tmp", ".temp", ".bak"))
                    totalBytesDeleted += result.first
                    filesDeleted += result.second

                    val progress = ((index + 1).toFloat() / totalDirs * 100).toInt()
                    sendProgressBroadcast(task, progress)
                }

                logMaintenanceAction("temp_cleanup", "Cleaned $filesDeleted temp files (${totalBytesDeleted / 1024}KB)")

                TaskResult(
                    success = true,
                    message = "Temp file cleanup completed: $filesDeleted files removed, ${totalBytesDeleted / 1024}KB freed",
                    bytesProcessed = totalBytesDeleted,
                    filesProcessed = filesDeleted
                )
            } catch (e: Exception) {
                Log.e(TAG, "Temp file cleanup failed", e)
                TaskResult(false, "Temp file cleanup failed: ${e.message}")
            }
        }
    }

    private suspend fun performDatabaseOptimization(task: MaintenanceTask): TaskResult {
        return withContext(Dispatchers.IO) {
            Log.i(TAG, "Starting database optimization")

            try {
                sendProgressBroadcast(task, 10)

                // Find all database files
                val dbDir = getDatabasePath("dummy").parentFile
                val databases = dbDir?.listFiles()?.filter { it.extension == "db" } ?: emptyList()

                var totalBytesOptimized = 0L
                val totalDbs = databases.size

                databases.forEachIndexed { index, dbFile ->
                    Log.d(TAG, "Optimizing database: ${dbFile.name}")

                    val sizeBefore = dbFile.length()

                    try {
                        // Open database and run VACUUM and ANALYZE
                        val db = android.database.sqlite.SQLiteDatabase.openDatabase(
                            dbFile.absolutePath,
                            null,
                            android.database.sqlite.SQLiteDatabase.OPEN_READWRITE
                        )
                        db.execSQL("VACUUM")
                        db.execSQL("ANALYZE")
                        db.close()

                        val sizeAfter = dbFile.length()
                        val saved = sizeBefore - sizeAfter
                        if (saved > 0) {
                            totalBytesOptimized += saved
                        }
                        Log.d(TAG, "Optimized ${dbFile.name}: ${sizeBefore / 1024}KB -> ${sizeAfter / 1024}KB")
                    } catch (e: Exception) {
                        Log.w(TAG, "Failed to optimize ${dbFile.name}: ${e.message}")
                    }

                    val progress = 10 + ((index + 1).toFloat() / totalDbs * 90).toInt()
                    sendProgressBroadcast(task, progress)
                }

                logMaintenanceAction("db_optimization", "Optimized $totalDbs databases, saved ${totalBytesOptimized / 1024}KB")

                TaskResult(
                    success = true,
                    message = "Database optimization completed: $totalDbs databases optimized, ${totalBytesOptimized / 1024}KB saved",
                    bytesProcessed = totalBytesOptimized,
                    filesProcessed = totalDbs
                )
            } catch (e: Exception) {
                Log.e(TAG, "Database optimization failed", e)
                TaskResult(false, "Database optimization failed: ${e.message}")
            }
        }
    }

    private suspend fun performFullMaintenance(task: MaintenanceTask): TaskResult {
        Log.i(TAG, "Starting full maintenance cycle")

        val results = mutableListOf<TaskResult>()
        val subTasks = listOf(
            TASK_CACHE_CLEANUP to 25,
            TASK_LOG_CLEANUP to 50,
            TASK_TEMP_FILE_CLEANUP to 75,
            TASK_DATABASE_OPTIMIZATION to 100
        )

        for ((taskType, progress) in subTasks) {
            val subTask = task.copy(type = taskType)
            val result = try {
                executeTask(subTask)
            } catch (e: Exception) {
                TaskResult(false, "$taskType failed: ${e.message}")
            }
            results.add(result)
            sendProgressBroadcast(task, progress)
            Log.i(TAG, "Full maintenance sub-task $taskType: success=${result.success}")
        }

        val allSuccess = results.all { it.success }
        val totalBytes = results.sumOf { it.bytesProcessed }
        val totalFiles = results.sumOf { it.filesProcessed }
        val failedTasks = results.filter { !it.success }.map { it.message }

        val message = if (allSuccess) {
            "Full maintenance completed: $totalFiles files processed, ${totalBytes / 1024}KB freed"
        } else {
            "Full maintenance partially completed. Failures: ${failedTasks.joinToString("; ")}"
        }

        logMaintenanceAction("full_maintenance", message)

        return TaskResult(
            success = allSuccess,
            message = message,
            bytesProcessed = totalBytes,
            filesProcessed = totalFiles
        )
    }

    private fun cleanDirectory(
        dir: File,
        cutoffTime: Long,
        maxTotalSizeBytes: Long,
        extensionFilter: List<String>? = null
    ): Pair<Long, Int> {
        var bytesDeleted = 0L
        var filesDeleted = 0

        if (!dir.exists() || !dir.isDirectory) return Pair(0L, 0)

        val files = dir.listFiles() ?: return Pair(0L, 0)

        for (file in files) {
            if (file.isDirectory) {
                val subResult = cleanDirectory(file, cutoffTime, maxTotalSizeBytes, extensionFilter)
                bytesDeleted += subResult.first
                filesDeleted += subResult.second

                // Remove empty directories
                if (file.listFiles()?.isEmpty() == true) {
                    file.delete()
                }
                continue
            }

            val matchesExtension = extensionFilter == null ||
                    extensionFilter.any { file.name.endsWith(it, ignoreCase = true) }

            if (matchesExtension && file.lastModified() < cutoffTime) {
                val fileSize = file.length()
                if (file.delete()) {
                    bytesDeleted += fileSize
                    filesDeleted++
                    Log.d(TAG, "Deleted: ${file.absolutePath} (${fileSize / 1024}KB)")
                }
            }
        }

        return Pair(bytesDeleted, filesDeleted)
    }

    private fun isPathSafe(file: File): Boolean {
        val canonicalPath = file.canonicalPath
        val appDataDir = filesDir.parentFile?.canonicalPath ?: return false
        val appCacheDir = cacheDir.canonicalPath
        val extCacheDir = externalCacheDir?.canonicalPath

        return canonicalPath.startsWith(appDataDir) ||
                canonicalPath.startsWith(appCacheDir) ||
                (extCacheDir != null && canonicalPath.startsWith(extCacheDir))
    }

    private fun logMaintenanceAction(action: String, details: String) {
        try {
            val logDir = File(filesDir, "logs")
            if (!logDir.exists()) logDir.mkdirs()

            val logFile = File(logDir, "maintenance_history.log")
            val dateFormat = SimpleDateFormat("yyyy-MM-dd HH:mm:ss", Locale.getDefault())
            val entry = "${dateFormat.format(Date())} | $action | $details\n"
            logFile.appendText(entry)
        } catch (e: Exception) {
            Log.w(TAG, "Failed to write maintenance log", e)
        }
    }

    private fun sendStatusBroadcast(task: MaintenanceTask, action: String, result: TaskResult? = null) {
        val intent = Intent(action).apply {
            putExtra(EXTRA_TASK_ID, task.id)
            putExtra(EXTRA_TASK_TYPE, task.type)
            putExtra(EXTRA_CALLER_PACKAGE, task.callerPackage)
            result?.let {
                putExtra(EXTRA_RESULT_SUCCESS, it.success)
                putExtra(EXTRA_RESULT_MESSAGE, it.message)
            }
            addFlags(Intent.FLAG_INCLUDE_STOPPED_PACKAGES)
        }
        sendBroadcast(intent)
    }

    private fun sendProgressBroadcast(task: MaintenanceTask, progress: Int) {
        val intent = Intent(ACTION_TASK_PROGRESS).apply {
            putExtra(EXTRA_TASK_ID, task.id)
            putExtra(EXTRA_TASK_TYPE, task.type)
            putExtra(EXTRA_PROGRESS_PERCENT, progress)
            putExtra(EXTRA_CALLER_PACKAGE, task.callerPackage)
            addFlags(Intent.FLAG_INCLUDE_STOPPED_PACKAGES)
        }
        sendBroadcast(intent)
    }

    private fun sendResultBroadcast(
        callerPackage: String?,
        callbackAction: String?,
        taskId: Long,
        result: TaskResult
    ) {
        callbackAction?.let { action ->
            val intent = Intent(action).apply {
                callerPackage?.let { setPackage(it) }
                putExtra(EXTRA_TASK_ID, taskId)
                putExtra(EXTRA_RESULT_SUCCESS, result.success)
                putExtra(EXTRA_RESULT_MESSAGE, result.message)
                addFlags(Intent.FLAG_INCLUDE_STOPPED_PACKAGES)
            }
            sendBroadcast(intent)
        }
    }

    private fun createNotificationChannel() {
        if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.O) {
            val channel = NotificationChannel(
                NOTIFICATION_CHANNEL_ID,
                "System Maintenance",
                NotificationManager.IMPORTANCE_LOW
            ).apply {
                description = "Background maintenance task notifications"
                setShowBadge(false)
            }

            val notificationManager = getSystemService(NotificationManager::class.java)
            notificationManager.createNotificationChannel(channel)
        }
    }

    private fun createNotification(contentText: String): Notification {
        return NotificationCompat.Builder(this, NOTIFICATION_CHANNEL_ID)
            .setContentTitle("System Optimizer")
            .setContentText(contentText)
            .setSmallIcon(android.R.drawable.ic_popup_sync)
            .setPriority(NotificationCompat.PRIORITY_LOW)
            .setOngoing(true)
            .build()
    }

    private fun updateNotification(contentText: String) {
        val notification = createNotification(contentText)
        val notificationManager = getSystemService(NotificationManager::class.java)
        notificationManager.notify(NOTIFICATION_ID, notification)
    }
}